function getName(code) {
  return CODE_NAMES[code.toUpperCase().trim()] || CODE_NAMES[code.trim()] || null;
}

const TYPE_STYLE = {
  number: { bg:"#222222", border:"#888888", text:"#cccccc", label:"🔢 Siguiente número" },
};

function isAvailable(code) {
  const u = code.toUpperCase().trim();
  return !existingSet.has(u) && !sessionGenerated.has(u);
}
function checkCode(code) {
  const u = code.toUpperCase().trim();
  if (existingSet.has(u)) return "exists";
  if (sessionGenerated.has(u)) return "session";
  return "available";
}
function addToSession(code) { sessionGenerated.add(code.toUpperCase().trim()); }

function parseCode(code) {
  const c = code.toUpperCase().trim();
  const spaceMatch = c.match(/^(.+?)\s+([A-Z0-9].*)$/);
  if (spaceMatch) return { base: spaceMatch[1], sep: " ", variant: spaceMatch[2] };
  const attachedMatch = c.match(/^([A-Z]*\d+)([A-Z]{2,})$/);
  if (attachedMatch) return { base: attachedMatch[1], sep: "", variant: attachedMatch[2] };
  return { base: c, sep: " ", variant: "" };
}

// Extract all numeric segments from a code so we can increment the right one.
// Strategy: try each numeric group from right to left (most specific first).
function generateAlternatives(code) {
  const c = code.toUpperCase().trim();
  const results = [];

  // Find all numeric groups with their positions
  const numRegex = /(\d+)/g;
  let match;
  const groups = [];
  while ((match = numRegex.exec(c)) !== null) {
    groups.push({ value: parseInt(match[1], 10), index: match.index, raw: match[1] });
  }

  if (groups.length === 0) {
    // No numbers at all — nothing to suggest
    return { results: [], siblings: [], parsed: { base: c, sep: "", variant: "" } };
  }

  // Try incrementing each numeric group (right-most = most specific, shown first)
  const tried = new Set();
  for (let g = groups.length - 1; g >= 0; g--) {
    const grp = groups[g];
    let found = 0;
    for (let delta = 1; delta <= 50 && found < 3; delta++) {
      const nextNum = grp.value + delta;
      // Preserve zero-padding if original had it (e.g. "01" → "02")
      const padded = grp.raw.startsWith("0") && grp.raw.length > 1
        ? String(nextNum).padStart(grp.raw.length, "0")
        : String(nextNum);
      const candidate = c.slice(0, grp.index) + padded + c.slice(grp.index + grp.raw.length);
      if (!tried.has(candidate) && isAvailable(candidate)) {
        tried.add(candidate);
        const segLabel = c.slice(0, grp.index) + `[${grp.raw}→${padded}]` + c.slice(grp.index + grp.raw.length);
        results.push({
          code: candidate,
          type: "number",
          reason: `${segLabel}`,
        });
        found++;
      }
    }
    if (results.length >= 6) break; // cap total at 6 suggestions
  }

  // Family siblings (same prefix up to first space or color token)
  const { base } = parseCode(c);
  const siblings = EXISTING_CODES
    .filter(ec => { const p = parseCode(ec); return p.base === base && ec.toUpperCase() !== c; })
    .slice(0, 6);

  return { results: results.slice(0, 6), siblings, parsed: parseCode(c) };
}

const STATUS = {
  exists:    { label:"YA EXISTE",              color:"#f87171", bg:"#1e0f0f", border:"#5c1f1f" },
  session:   { label:"REGISTRADO ESTA SESIÓN", color:"#fbbf24", bg:"#1a1400", border:"#54400a" },
  available: { label:"DISPONIBLE",             color:"#4ade80", bg:"#0b1a0f", border:"#1a5c30" },
  partial:   { label:"COINCIDENCIAS",          color:"#94a3b8", bg:"#181818", border:"#2e2e2e" },
};

export default function App() {
  const [tab, setTab] = useState("check");
  const [mode, setMode] = useState("verify"); // "verify" | "generate"
  const [inputCode, setInputCode] = useState("");
  const [genBase, setGenBase] = useState("");
  const [genResult, setGenResult] = useState(null);
  const [nameQuery, setNameQuery] = useState("");
  const [nameMatches, setNameMatches] = useState(null); // [{code, name}]
  const [selectedFamily, setSelectedFamily] = useState(null); // {base, siblings}
  const [colorSuffix, setColorSuffix] = useState("");
  const [genStep, setGenStep] = useState(1); // 1=search name, 2=pick family, 3=pick color+generate
  const [checkResult, setCheckResult] = useState(null);
  const [alternatives, setAlternatives] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [newCodes, setNewCodes] = useState([]);
  const [toast, setToast] = useState(null);

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(null), 2400); };

  const handleCheck = () => {
    const input = inputCode.trim().toUpperCase();
    if (!input) return;

    // Exact match first
    const exactStatus = checkCode(input);
    if (exactStatus !== "available") {
      // Found exact match — show it plus alternatives
      setCheckResult({ code: input, status: exactStatus, matches: null });
      setAlternatives(generateAlternatives(input));
    } else {
      // Check if it truly doesn't exist or is a partial query
      // Search for all codes containing the input as substring
      const matches = EXISTING_CODES.filter(c =>
        c.toUpperCase().includes(input)
      );
      if (matches.length > 0 && matches.length < EXISTING_CODES.length) {
        // Partial search — show matches instead of "available"
        setCheckResult({ code: input, status: "partial", matches });
        setAlternatives(null);
      } else {
        // Genuinely new code
        setCheckResult({ code: input, status: "available", matches: null });
        setAlternatives(null);
      }
    }
  };

  const handleRegister = (code) => {
    addToSession(code);
    setNewCodes(prev => [...prev, "221-" + code]);
    showToast(`✓ 221-${code} registrado`);
    setAlternatives(prev => prev ? { ...prev, results: prev.results.filter(r => r.code !== code) } : null);
  };

  const handleRegisterCurrent = () => {
    if (!checkResult || (checkResult.status !== "available" && checkResult.status !== "session")) return;
    if (checkResult.status !== "available") return;
    handleRegister(checkResult.code);
    setCheckResult(null); setInputCode(""); setAlternatives(null);
  };

  const handleCopy = (text) => { navigator.clipboard.writeText(text); showToast("Copiado al portapapeles"); };

  const handleGenerate = () => {
    const base = genBase.trim().toUpperCase();
    if (!base) return;
    const result = generateAlternatives(base);
    setGenResult({ base, ...result });
  };

  const searchByName = () => {
    const q = nameQuery.trim().toUpperCase();
    if (!q) return;
    // Score each entry: count how many words of query appear in the name
    const words = q.split(/\s+/).filter(Boolean);
    const scored = Object.entries(CODE_NAMES)
      .map(([code, name]) => {
        const uname = name.toUpperCase();
        const score = words.filter(w => uname.includes(w)).length;
        return { code, name, score };
      })
      .filter(x => x.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 20);
    setNameMatches(scored);
    setSelectedFamily(null);
    setColorSuffix("");
    setGenStep(2);
  };

  const COLORS = [
    "NGR","BCO","GRS","AZL","VDE","VRD","MRN","BGE","CEL","RSA","BDO","CAM",
    "MAR","MARR","GR CL","GR OSC","GR MEL","NAT","PETRO","OLIVA","CRUDO","LADR",
    "AZL MAR","AZL FR","AZL OSC","VDE AG","VDE OSC",
  ];

  const pickFamily = (code) => {
    // Extract the numeric base from this code (strip trailing color suffix)
    const parsed = parseCode(code);
    // Find all existing codes that share the same numeric prefix
    const base = parsed.base;
    const sibs = EXISTING_CODES.filter(ec => {
      const p = parseCode(ec);
      return p.base === base;
    });
    setSelectedFamily({ base, code, siblings: sibs });
    setGenStep(3);
    setGenResult(null);
    setColorSuffix("");
  };

  const buildAndGenerate = () => {
    if (!selectedFamily) return;
    // Compose final base: numeric base + space + color suffix if provided
    const suffix = colorSuffix.trim().toUpperCase();
    const baseWithColor = suffix ? selectedFamily.base + " " + suffix : selectedFamily.base;
    const result = generateAlternatives(baseWithColor);
    setGenBase(baseWithColor);
    setGenResult({ base: baseWithColor, ...result });
  };

  const filteredCodes = useMemo(() => {
    if (!searchTerm) return EXISTING_CODES.slice(0, 80);
    const q = searchTerm.toLowerCase();
    return EXISTING_CODES.filter(c => {
      const name = (CODE_NAMES[c] || CODE_NAMES[c.toUpperCase()] || "").toLowerCase();
      return name.includes(q) || c.toLowerCase().includes(q);
    });
  }, [searchTerm]);

  const altTypes = [];
  const filteredAlts = alternatives ? alternatives.results : [];

  return (
    <div style={{ minHeight:"100vh", background:"#111111", color:"#e8e8e8", fontFamily:"'Inter', sans-serif" }}>

      {/* Header */}
      <div style={{ background:"#141414", borderBottom:"1px solid #2a2a2a", padding:"22px 28px 0" }}>
        <div style={{ maxWidth:820, margin:"0 auto" }}>
          <div style={{ fontSize:10, letterSpacing:4, color:"#e0e0e0", marginBottom:3 }}>SISTEMA DE GESTIÓN · PREFIJO 221</div>
          <h1 style={{ fontSize:24, fontWeight:700, margin:"0 0 3px", color:"#fff" }}>
            Generador de Códigos <span style={{ color:"#e0e0e0" }}>221</span>
          </h1>
          <p style={{ margin:"0 0 18px", color:"#888888", fontSize:11 }}>
            {EXISTING_CODES.length} existentes · {newCodes.length} nuevos esta sesión
          </p>
          <div style={{ display:"flex" }}>
            {[
              { id:"check", label:"Verificar / Crear" },
              { id:"search", label:"Buscar existentes" },
              { id:"list", label:`Nuevos (${newCodes.length})` },
            ].map(t => (
              <button key={t.id} onClick={() => setTab(t.id)} style={{
                padding:"8px 18px", background: tab===t.id ? "#e8e8e8" : "transparent",
                color: tab===t.id ? "#111111" : "#666666", border:"none",
                borderBottom: tab===t.id ? "2px solid #e8e8e8" : "2px solid transparent",
                cursor:"pointer", fontSize:12, fontFamily:"'Inter', sans-serif",
                borderRadius: tab===t.id ? "4px 4px 0 0" : 0, transition:"all .2s",
              }}>{t.label}</button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ maxWidth:820, margin:"0 auto", padding:"26px 28px" }}>

        {/* ── Verificar ── */}
        {tab === "check" && (<>

          {/* Mode toggle */}
          <div style={{ display:"flex", gap:6, marginBottom:14 }}>
            {[["verify","🔍 Verificar código"],["generate","✨ Generar código nuevo"]].map(([m,label]) => (
              <button key={m} onClick={() => { setMode(m); setCheckResult(null); setAlternatives(null); setGenResult(null); setInputCode(""); setGenBase(""); setNameQuery(""); setNameMatches(null); setSelectedFamily(null); setColorSuffix(""); setGenStep(1); }}
                style={{ padding:"8px 18px", background: mode===m ? "#e8e8e8" : "#1a1a1a", color: mode===m ? "#111111" : "#666666",
                  border:`1px solid ${mode===m ? "#e8e8e8" : "#2a2a2a"}`, borderRadius:8, cursor:"pointer",
                  fontSize:12, fontFamily:"'Inter', sans-serif", fontWeight: mode===m ? 700 : 400, transition:"all .2s" }}>
                {label}
              </button>
            ))}
          </div>

          {/* ── VERIFY MODE ── */}
          {mode === "verify" && (
          <div style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:10, padding:20, marginBottom:14 }}>
            <div style={{ fontSize:10, letterSpacing:3, color:"#e0e0e0", marginBottom:9 }}>CÓDIGO (SIN "221-")</div>
            <div style={{ display:"flex", gap:8 }}>
              <div style={{ background:"#111111", border:"1px solid #2a2a2a", borderRadius:6, padding:"10px 12px", color:"#e0e0e0", fontSize:14, display:"flex", alignItems:"center", whiteSpace:"nowrap" }}>221-</div>
              <input
                value={inputCode}
                onChange={e => { setInputCode(e.target.value.toUpperCase()); setCheckResult(null); setAlternatives(null); }}
                onKeyDown={e => e.key==="Enter" && handleCheck()}
                placeholder="M3064 NGR"
                style={{ flex:1, background:"#111111", border:"1px solid #2a2a2a", borderRadius:6, padding:"10px 14px", color:"#e8e8e8", fontSize:15, fontFamily:"'Inter', sans-serif", letterSpacing:1, outline:"none" }}
              />
              <button onClick={handleCheck} style={{ background:"#e8e8e8", color:"#fff", border:"none", borderRadius:6, padding:"10px 22px", cursor:"pointer", fontSize:12, fontFamily:"'Inter', sans-serif", fontWeight:700 }}>VERIFICAR</button>
            </div>
          </div>
          )}

          {/* ── GENERATE MODE ── */}
          {mode === "generate" && (<>

            {/* Step indicators */}
            <div style={{ display:"flex", gap:0, marginBottom:16, background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:10, overflow:"hidden" }}>
              {[["1","Buscar artículo"],["2","Elegir familia"],["3","Color y generar"]].map(([n, label], idx) => {
                const stepNum = idx + 1;
                const active = genStep === stepNum;
                const done = genStep > stepNum;
                return (
                  <div key={n} style={{ flex:1, padding:"10px 14px", textAlign:"center", background: active ? "#242424" : done ? "#1e1e1e" : "transparent",
                    borderRight: idx < 2 ? "1px solid #2a2a2a" : "none", cursor: done ? "pointer" : "default" }}
                    onClick={() => { if (done) { setGenStep(stepNum); if (stepNum === 1) { setNameMatches(null); setSelectedFamily(null); setGenResult(null); } if (stepNum === 2) { setSelectedFamily(null); setGenResult(null); } } }}
                  >
                    <div style={{ fontSize:16, color: active ? "#ffffff" : done ? "#aaaaaa" : "#444444" }}>{done ? "✓" : n}</div>
                    <div style={{ fontSize:10, color: active ? "#cccccc" : done ? "#aaaaaa" : "#444444", marginTop:2 }}>{label}</div>
                  </div>
                );
              })}
            </div>

            {/* STEP 1: search by name */}
            <div style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:10, padding:20, marginBottom:14 }}>
              <div style={{ fontSize:10, letterSpacing:3, color:"#ffffff", marginBottom:4 }}>PASO 1 · NOMBRE DEL ARTÍCULO</div>
              <div style={{ fontSize:11, color:"#888888", marginBottom:10 }}>
                Escribí palabras clave del nombre (ej: <span style={{color:"#c8c8c8"}}>buzo canguro frisa</span>, <span style={{color:"#c8c8c8"}}>calza biker negro</span>)
              </div>
              <div style={{ display:"flex", gap:8 }}>
                <input
                  value={nameQuery}
                  onChange={e => setNameQuery(e.target.value)}
                  onKeyDown={e => e.key==="Enter" && searchByName()}
                  placeholder="REMERA DEPORTIVA NEGRO..."
                  style={{ flex:1, background:"#111111", border:"1px solid #2a2a2a", borderRadius:6, padding:"10px 14px",
                    color:"#e8e8e8", fontSize:14, fontFamily:"'Inter', sans-serif", letterSpacing:.5, outline:"none" }}
                />
                <button onClick={searchByName} style={{ background:"#e8e8e8", color:"#fff", border:"none", borderRadius:6,
                  padding:"10px 20px", cursor:"pointer", fontSize:12, fontFamily:"'Inter', sans-serif", fontWeight:700 }}>BUSCAR</button>
              </div>
            </div>

            {/* STEP 2: pick family from name matches */}
            {nameMatches && genStep >= 2 && (
              <div style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:10, padding:20, marginBottom:14 }}>
                <div style={{ fontSize:10, letterSpacing:3, color:"#cccccc", marginBottom:3 }}>PASO 2 · ELEGÍ LA FAMILIA MÁS PARECIDA</div>
                <div style={{ fontSize:11, color:"#888888", marginBottom:12 }}>
                  {nameMatches.length} artículo(s) similar(es). Hacé clic en el que más se parece para usar su estructura de código.
                </div>
                {nameMatches.length === 0 ? (
                  <div style={{ color:"#888888", fontSize:13, textAlign:"center", padding:"16px 0" }}>
                    Sin resultados. Probá con otras palabras clave.
                  </div>
                ) : (
                  <div style={{ display:"flex", flexDirection:"column", gap:5, maxHeight:320, overflowY:"auto" }}>
                    {nameMatches.map(({code, name}) => (
                      <div key={code}
                        onClick={() => pickFamily(code)}
                        style={{ background: selectedFamily?.code === code ? "#242424" : "#111111",
                          border:`1px solid ${selectedFamily?.code === code ? "#e8e8e8" : "#2a2a2a"}`,
                          borderRadius:7, padding:"10px 14px", cursor:"pointer",
                          display:"flex", justifyContent:"space-between", alignItems:"center", gap:12,
                          transition:"all .15s" }}
                        onMouseEnter={e => { if (selectedFamily?.code !== code) e.currentTarget.style.borderColor="#888888"; }}
                        onMouseLeave={e => { if (selectedFamily?.code !== code) e.currentTarget.style.borderColor="#2a2a2a"; }}
                      >
                        <div style={{ minWidth:0 }}>
                          <div style={{ fontSize:11, color:"#e8e8e8", fontWeight:600, marginBottom:2 }}>{name}</div>
                          <div style={{ fontSize:12, color:"#e0e0e0", fontFamily:"'Inter', sans-serif" }}>221-{code}</div>
                        </div>
                        <div style={{ fontSize:11, color:"#ffffff", flexShrink:0 }}>
                          {selectedFamily?.code === code ? "✓ Seleccionado" : "Usar esta familia →"}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* STEP 3: color suffix + generate */}
            {selectedFamily && genStep >= 3 && (
              <div style={{ background:"#1a1a1a", border:"1px solid #3a3a3a", borderRadius:10, padding:20, marginBottom:14 }}>
                <div style={{ fontSize:10, letterSpacing:3, color:"#ffffff", marginBottom:3 }}>PASO 3 · COLOR / VARIANTE</div>
                <div style={{ fontSize:11, color:"#888888", marginBottom:10 }}>
                  Base de familia detectada: <span style={{color:"#c8c8c8", fontFamily:"'Inter', sans-serif"}}>221-{selectedFamily.base}</span>
                  {" · "}Agregá el color/variante o dejalo vacío para generar sólo el número.
                </div>

                {/* Color chips */}
                <div style={{ display:"flex", flexWrap:"wrap", gap:5, marginBottom:12 }}>
                  {COLORS.map(c => (
                    <button key={c} onClick={() => setColorSuffix(colorSuffix === c ? "" : c)}
                      style={{ padding:"4px 10px", background: colorSuffix === c ? "#e8e8e8" : "#222222",
                        border:`1px solid ${colorSuffix === c ? "#e8e8e8" : "#333333"}`, borderRadius:6,
                        color: colorSuffix === c ? "#111111" : "#888888", fontSize:11,
                        fontFamily:"'Inter', sans-serif", cursor:"pointer", transition:"all .15s" }}>
                      {c}
                    </button>
                  ))}
                </div>

                {/* Manual suffix input */}
                <div style={{ display:"flex", gap:8, marginBottom:14 }}>
                  <div style={{ background:"#111111", border:"1px solid #2a2a2a", borderRadius:6, padding:"9px 12px",
                    color:"#e0e0e0", fontSize:13, display:"flex", alignItems:"center", whiteSpace:"nowrap",
                    fontFamily:"'Inter', sans-serif" }}>221-{selectedFamily.base}</div>
                  <input
                    value={colorSuffix}
                    onChange={e => setColorSuffix(e.target.value.toUpperCase())}
                    onKeyDown={e => e.key==="Enter" && buildAndGenerate()}
                    placeholder="NGR (o vacío)"
                    style={{ flex:1, background:"#111111", border:"1px solid #2a2a2a", borderRadius:6,
                      padding:"9px 14px", color:"#e8e8e8", fontSize:14, fontFamily:"'Inter', sans-serif",
                      letterSpacing:1, outline:"none" }}
                  />
                  <button onClick={buildAndGenerate} style={{ background:"#e8e8e8", color:"#fff", border:"none",
                    borderRadius:6, padding:"9px 20px", cursor:"pointer", fontSize:12,
                    fontFamily:"'Inter', sans-serif", fontWeight:700 }}>GENERAR</button>
                </div>

                {/* Existing siblings for context */}
                {selectedFamily.siblings.length > 0 && (
                  <div style={{ paddingTop:10, borderTop:"1px solid #2a2a2a" }}>
                    <div style={{ fontSize:10, letterSpacing:2, color:"#555555", marginBottom:7 }}>FAMILIA EXISTENTE</div>
                    <div style={{ display:"flex", flexWrap:"wrap", gap:4 }}>
                      {selectedFamily.siblings.slice(0,10).map(s => (
                        <span key={s} onClick={() => setColorSuffix(parseCode(s).variant)}
                          title={"Click para usar variante: " + parseCode(s).variant}
                          style={{ background:"#222222", border:"1px solid #303030", borderRadius:5,
                            padding:"3px 9px", fontSize:11, color:"#888888", cursor:"pointer" }}>
                          <span style={{color:"#e0e0e0"}}>221-</span>{s}
                        </span>
                      ))}
                    </div>
                  </div>
                )}

                {/* Generated codes */}
                {genResult && genResult.results.length > 0 && (
                  <div style={{ marginTop:16, paddingTop:14, borderTop:"1px solid #2a2a2a" }}>
                    <div style={{ fontSize:10, letterSpacing:3, color:"#ffffff", marginBottom:10 }}>CÓDIGOS DISPONIBLES</div>
                    <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(220px,1fr))", gap:7 }}>
                      {genResult.results.map(alt => (
                        <div key={alt.code}
                          style={{ background:"#1a1a1a", border:"1px solid #3a3a3a", borderRadius:8,
                            padding:"13px 14px", display:"flex", flexDirection:"column", gap:6, transition:"border-color .15s" }}
                          onMouseEnter={e => e.currentTarget.style.borderColor="#888888"}
                          onMouseLeave={e => e.currentTarget.style.borderColor="#14532d"}
                        >
                          <div style={{ fontSize:16, letterSpacing:1, fontWeight:700, color:"#fff" }}>
                            <span style={{color:"#e0e0e0"}}>221-</span>{alt.code}
                          </div>
                          <div style={{ fontSize:10, color:"#888888" }}>{alt.reason}</div>
                          <div style={{ display:"flex", gap:5, marginTop:2 }}>
                            <button onClick={() => handleCopy("221-"+alt.code)}
                              style={{ flex:1, background:"transparent", border:"1px solid #3a3a3a", borderRadius:5,
                                padding:"6px 0", cursor:"pointer", fontSize:11, fontFamily:"'Inter', sans-serif", color:"#ffffff" }}>
                              COPIAR
                            </button>
                            <button onClick={() => { handleRegister(alt.code); setGenResult(prev => prev ? { ...prev, results: prev.results.filter(r => r.code !== alt.code) } : null); }}
                              style={{ flex:1, background:"#e8e8e8", border:"none", borderRadius:5,
                                padding:"6px 0", cursor:"pointer", fontSize:11, fontFamily:"'Inter', sans-serif", color:"#111111", fontWeight:700 }}>
                              REGISTRAR
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
                {genResult && genResult.results.length === 0 && (
                  <div style={{ marginTop:14, color:"#aaaaaa", fontSize:12, textAlign:"center" }}>
                    No hay número siguiente disponible para esta combinación. Probá sin sufijo de color o con otro color.
                  </div>
                )}
              </div>
            )}
          </>)}

          {mode === "verify" && (<>
          {/* Status banner */}
          {checkResult && checkResult.status !== "partial" && (
            <div style={{ background:STATUS[checkResult.status].bg, border:`1px solid ${STATUS[checkResult.status].border}`, borderRadius:10, padding:"14px 18px", marginBottom:14, display:"flex", alignItems:"center", justifyContent:"space-between" }}>
              <div>
                <div style={{ fontSize:10, letterSpacing:3, color:STATUS[checkResult.status].color, marginBottom:4 }}>● {STATUS[checkResult.status].label}</div>
                <div style={{ fontSize:19, fontWeight:700, letterSpacing:1, color:"#fff" }}>221-{checkResult.code}</div>
                {getName(checkResult.code) && (
                  <div style={{ fontSize:12, color:"#c8c8c8", marginTop:5, letterSpacing:.3 }}>
                    📦 {getName(checkResult.code)}
                  </div>
                )}
              </div>
              {checkResult.status === "available" && (
                <div style={{ display:"flex", gap:7 }}>
                  <button onClick={() => handleCopy("221-"+checkResult.code)} style={{ background:"transparent", border:"1px solid #1a5c30", borderRadius:6, padding:"7px 16px", cursor:"pointer", fontSize:11, fontWeight:600, color:"#4ade80" }}>COPIAR</button>
                  <button onClick={handleRegisterCurrent} style={{ background:"#4ade80", border:"none", borderRadius:6, padding:"7px 16px", cursor:"pointer", fontSize:11, color:"#0b1a0f", fontWeight:700 }}>REGISTRAR ✓</button>
                </div>
              )}
            </div>
          )}

          {/* Partial matches list */}
          {checkResult?.status === "partial" && (
            <div style={{ background:"#181818", border:"1px solid #2e2e2e", borderRadius:10, padding:20, marginBottom:14 }}>
              <div style={{ fontSize:10, letterSpacing:3, color:"#94a3b8", marginBottom:12 }}>
                🔍 {checkResult.matches.length} COINCIDENCIA(S) PARA "{checkResult.code}"
              </div>
              <div style={{ display:"flex", flexDirection:"column", gap:6, maxHeight:340, overflowY:"auto" }}>
                {checkResult.matches.map(code => (
                  <div key={code}
                    style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:7, padding:"10px 13px", display:"flex", alignItems:"center", justifyContent:"space-between", gap:10, transition:"border-color .15s", cursor:"default" }}
                    onMouseEnter={e => e.currentTarget.style.borderColor="#888888"}
                    onMouseLeave={e => e.currentTarget.style.borderColor="#2a2a2a"}
                  >
                    <div style={{ minWidth:0 }}>
                      {/* Highlight the matching part */}
                      <div style={{ fontSize:14, letterSpacing:.8, fontWeight:600, color:"#fff" }}>
                        <span style={{ color:"#e0e0e0" }}>221-</span>
                        {code.split(new RegExp(`(${checkResult.code.replace(/[.*+?^${}()|[\]\\]/g,"\\$&")})`, "i")).map((part, i) =>
                          part.toUpperCase() === checkResult.code.toUpperCase() ? (
                            <span key={i} style={{ background:"#facc15", color:"#111111", borderRadius:3, padding:"0 3px", fontWeight:700 }}>{part}</span>
                          ) : <span key={i}>{part}</span>
                        )}
                      </div>
                      {getName(code) && <div style={{ fontSize:11, color:"#888888", marginTop:3 }}>📦 {getName(code)}</div>}
                    </div>
                    <div style={{ display:"flex", gap:5, flexShrink:0 }}>
                      <button onClick={() => handleCopy("221-"+code)} style={{ background:"transparent", border:"1px solid #303030", borderRadius:5, padding:"4px 10px", cursor:"pointer", fontSize:10, fontFamily:"'Inter', sans-serif", color:"#888888" }}>COPIAR</button>
                      <button onClick={() => { setInputCode(code); setCheckResult(null); setAlternatives(null); setTimeout(() => { const code2 = code; const status = checkCode(code2); setCheckResult({ code: code2, status, matches: null }); setAlternatives(status !== "available" ? generateAlternatives(code2) : null); }, 0); }} style={{ background:"#262626", border:"1px solid #3a3a3a", borderRadius:5, padding:"4px 10px", cursor:"pointer", fontSize:10, fontFamily:"'Inter', sans-serif", color:"#c8c8c8" }}>VER</button>
                    </div>
                  </div>
                ))}
              </div>
              {checkResult.matches.length >= 1 && (
                <div style={{ marginTop:12, paddingTop:10, borderTop:"1px solid #2a2a2a", fontSize:11, color:"#888888" }}>
                  ¿No encontraste lo que buscabas? <span style={{ color:"#c8c8c8", cursor:"pointer", textDecoration:"underline" }} onClick={() => { const status = checkCode(checkResult.code); if (status === "available") { setCheckResult({ code: checkResult.code, status: "available", matches: null }); } }}>Registrar "221-{checkResult.code}" como código nuevo</span>
                </div>
              )}
            </div>
          )}

          {/* Alternatives */}
          {alternatives && checkResult?.status !== "available" && (
            <div style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:10, padding:20 }}>
              <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", marginBottom:14, flexWrap:"wrap", gap:8 }}>
                <div>
                  <div style={{ fontSize:10, letterSpacing:3, color:"#cccccc", marginBottom:3 }}>ALTERNATIVAS DISPONIBLES</div>
                  <div style={{ fontSize:11, color:"#888888" }}>
                    Código buscado: <span style={{ color:"#c8c8c8" }}>221-{alternatives.parsed.base}{alternatives.parsed.sep}{alternatives.parsed.variant}</span>
                    {" "}· <span style={{ color:"#e8e8e8" }}>{filteredAlts.length}</span> sugerencia(s) con siguiente número libre
                  </div>
                </div>
              </div>

              {filteredAlts.length === 0 ? (
                <div style={{ color:"#888888", fontSize:13, padding:"18px 0", textAlign:"center" }}>Sin alternativas para este filtro.</div>
              ) : (
                <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill, minmax(220px,1fr))", gap:7 }}>
                  {filteredAlts.map(alt => (
                    <div key={alt.code}
                      style={{ background:"#111111", border:`1px solid ${TYPE_STYLE[alt.type].border}30`, borderRadius:8, padding:"11px 13px", display:"flex", flexDirection:"column", gap:5, transition:"border-color .15s", cursor:"default" }}
                      onMouseEnter={e => e.currentTarget.style.borderColor = "#888888"}
                      onMouseLeave={e => e.currentTarget.style.borderColor = "#2a2a2a"}
                    >
                      <span style={{ fontSize:10, alignSelf:"flex-start", background:"#222222", color:"#e8e8e8", border:"1px solid #333333", padding:"2px 7px", borderRadius:10 }}>
                        {TYPE_STYLE[alt.type].label}
                      </span>
                      <div style={{ fontSize:14, letterSpacing:.8, color:"#fff", fontWeight:600 }}>
                        <span style={{ color:"#e0e0e0" }}>221-</span>{alt.code}
                      </div>
                      <div style={{ fontSize:11, color:"#888888", lineHeight:1.4 }}>{alt.reason}</div>
                      <div style={{ display:"flex", gap:5, marginTop:3 }}>
                        <button onClick={() => handleCopy("221-"+alt.code)} style={{ flex:1, background:"transparent", border:"1px solid #3a3a3a", borderRadius:5, padding:"5px 0", cursor:"pointer", fontSize:10, fontFamily:"'Inter', sans-serif", color:"#e8e8e8" }}>COPIAR</button>
                        <button onClick={() => handleRegister(alt.code)} style={{ flex:1, background:"#222222", border:`1px solid ${TYPE_STYLE[alt.type].border}`, borderRadius:5, padding:"5px 0", cursor:"pointer", fontSize:10, fontFamily:"'Inter', sans-serif", color:"#e8e8e8", fontWeight:700 }}>REGISTRAR</button>
                      </div>
                    </div>
                  ))}
                </div>
              )}

              {alternatives.siblings.length > 0 && (
                <div style={{ marginTop:18, paddingTop:14, borderTop:"1px solid #2a2a2a" }}>
                  <div style={{ fontSize:10, letterSpacing:3, color:"#888888", marginBottom:8 }}>FAMILIA EXISTENTE (misma base 221-{alternatives.parsed.base})</div>
                  <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
                    {alternatives.siblings.map(s => (
                      <span key={s} style={{ background:"#222222", border:"1px solid #303030", borderRadius:6, padding:"3px 9px", fontSize:11, color:"#999999" }}>
                        <span style={{ color:"#e0e0e0" }}>221-</span>{s}
                      </span>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {!checkResult && (
            <div style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:8, padding:14, marginTop:6 }}>
              <div style={{ fontSize:10, color:"#e0e0e0", letterSpacing:2, marginBottom:7 }}>ABREVIATURAS COMUNES</div>
              <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:4, fontSize:11, color:"#888888" }}>
                {[["NGR","Negro"],["BCO","Blanco"],["GRS","Gris"],["AZL","Azul"],["VDE/VRD","Verde"],["MRN","Marrón"],["BGE","Beige"],["CEL","Celeste"],["RSA","Rosa"],["OSC","Oscuro"],["MEL","Melange"],["ESP","Especial"]].map(([a,d]) => (
                  <div key={a} style={{ display:"flex", gap:5 }}><span style={{ color:"#c8c8c8", minWidth:58 }}>{a}</span><span>{d}</span></div>
                ))}
              </div>
            </div>
          )}
          </>)}
        </>)}

        {/* ── Buscar ── */}
        {tab === "search" && (
          <div>
            <input
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              placeholder="Buscar por nombre de artículo o código..."
              style={{ width:"100%", background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:8,
                padding:"11px 16px", color:"#e8e8e8", fontSize:14, fontFamily:"'Inter', sans-serif",
                outline:"none", marginBottom:10, boxSizing:"border-box", letterSpacing:.3 }}
            />
            <div style={{ color:"#888888", fontSize:11, marginBottom:11, letterSpacing:.5 }}>
              {searchTerm
                ? `${filteredCodes.length} resultado(s) para "${searchTerm}"`
                : `Mostrando primeros 80 de ${EXISTING_CODES.length} — buscá por nombre o código`}
            </div>
            <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
              {filteredCodes.map(code => {
                const name = getName(code) || "";
                const q = searchTerm.toLowerCase();
                // Highlight matching part of name
                const highlightName = (text) => {
                  if (!q || !text.toLowerCase().includes(q)) return <span>{text}</span>;
                  const idx = text.toLowerCase().indexOf(q);
                  return <>
                    {text.slice(0, idx)}
                    <span style={{ background:"#facc15", color:"#111111", borderRadius:3, padding:"0 3px", fontWeight:600 }}>{text.slice(idx, idx+q.length)}</span>
                    {text.slice(idx+q.length)}
                  </>;
                };
                const highlightCode = (text) => {
                  if (!q || !text.toLowerCase().includes(q)) return <span>{text}</span>;
                  const idx = text.toLowerCase().indexOf(q);
                  return <>
                    {text.slice(0, idx)}
                    <span style={{ background:"#facc15", color:"#111111", borderRadius:3, padding:"0 3px", fontWeight:600 }}>{text.slice(idx, idx+q.length)}</span>
                    {text.slice(idx+q.length)}
                  </>;
                };
                return (
                  <div key={code}
                    onClick={() => handleCopy("221-"+code)}
                    title="Clic para copiar el código"
                    style={{ background:"#1a1a1a", border:"1px solid #2a2a2a", borderRadius:8,
                      padding:"10px 14px", cursor:"pointer",
                      display:"flex", justifyContent:"space-between", alignItems:"center", gap:12,
                      transition:"border-color .15s" }}
                    onMouseEnter={e => e.currentTarget.style.borderColor="#888888"}
                    onMouseLeave={e => e.currentTarget.style.borderColor="#2a2a2a"}
                  >
                    <div style={{ minWidth:0 }}>
                      {name && (
                        <div style={{ fontSize:13, color:"#e8e8e8", fontWeight:600, marginBottom:3,
                          overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                          {highlightName(name)}
                        </div>
                      )}
                      <div style={{ fontSize:11, fontFamily:"'Inter', sans-serif", color:"#888888" }}>
                        <span style={{ color:"#e0e0e0" }}>221-</span>{highlightCode(code)}
                      </div>
                    </div>
                    <div style={{ fontSize:10, color:"#444444", flexShrink:0 }}>⎘ copiar</div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* ── Nuevos ── */}
        {tab === "list" && (
          <div>
            {newCodes.length === 0 ? (
              <div style={{ textAlign:"center", padding:60, color:"#888888" }}>
                <div style={{ fontSize:36, marginBottom:10 }}>📋</div>
                <div>Todavía no registraste códigos nuevos.</div>
                <div style={{ fontSize:11, marginTop:5 }}>Verificá uno en la primera pestaña.</div>
              </div>
            ) : (
              <>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
                  <span style={{ color:"#888888", fontSize:11 }}>{newCodes.length} código(s) registrados esta sesión</span>
                  <button onClick={() => { navigator.clipboard.writeText(newCodes.join("\n")); showToast("Lista copiada"); }} style={{ background:"#e8e8e8", color:"#fff", border:"none", borderRadius:6, padding:"6px 14px", cursor:"pointer", fontSize:11, fontFamily:"'Inter', sans-serif" }}>COPIAR TODO</button>
                </div>
                {newCodes.map((code,i) => (
                  <div key={i} style={{ background:"#1a1a1a", border:"1px solid #3a3a3a", borderRadius:8, padding:"10px 14px", marginBottom:6, display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                    <span style={{ fontSize:15, letterSpacing:1 }}><span style={{ color:"#e0e0e0" }}>221-</span>{code.replace("221-","")}</span>
                    <div style={{ display:"flex", gap:6, alignItems:"center" }}>
                      <span style={{ fontSize:10, color:"#ffffff", background:"#14532d30", padding:"2px 7px", borderRadius:4 }}>NUEVO</span>
                      <button onClick={() => handleCopy(code)} style={{ background:"transparent", border:"1px solid #2a2a2a", borderRadius:4, padding:"3px 8px", cursor:"pointer", color:"#888888", fontSize:10, fontFamily:"'Inter', sans-serif" }}>COPIAR</button>
                    </div>
                  </div>
                ))}
              </>
            )}
          </div>
        )}
      </div>

      {toast && (
        <div style={{ position:"fixed", bottom:20, left:"50%", transform:"translateX(-50%)", background:"#222222", color:"#e8e8e8", border:"1px solid #404040", padding:"9px 20px", borderRadius:8, fontSize:12, fontFamily:"'Inter', sans-serif", boxShadow:"0 4px 20px rgba(0,0,0,.6)", zIndex:1000, animation:"fi .2s ease", whiteSpace:"nowrap" }}>
          {toast}
        </div>
      )}
      <style>{`
  @keyframes fi{from{opacity:0;transform:translate(-50%,8px)}to{opacity:1;transform:translate(-50%,0)}}
  input::placeholder{color:#555555}
  * { font-family: 'Inter', sans-serif !important; }
`}</style>
    </div>
  );
}
